import numpy as np
import matplotlib.pyplot as plt
from matplotlib.gridspec import GridSpec

print("Fourier Transform Illustration")
print("=" * 50)

# ─────────────────────────────────────────────────────────────
# EXPLANATION (printed to console)
# ─────────────────────────────────────────────────────────────
explanation = """
WHAT IS A FOURIER TRANSFORM?
─────────────────────────────
A Fourier Transform decomposes a signal (a function of time)
into the frequencies that make it up — much like a prism splits
white light into its constituent colours.

Key idea:
  Any periodic (or finite-duration) signal can be expressed as
  a sum of sine and cosine waves of different:
    • Frequencies  (how fast the wave oscillates)
    • Amplitudes   (how strong each frequency is)
    • Phases       (the timing offset of each wave)

The Discrete Fourier Transform (DFT) does this for sampled data.
NumPy's np.fft.fft() computes it efficiently (Fast Fourier Transform).

Formula (continuous):
  F(f) = integral[ x(t) * e^(-j*2*pi*f*t) ] dt

What we get back:
  • X-axis of frequency plot → frequency (Hz)
  • Y-axis of frequency plot → amplitude (strength of that frequency)

Real-world uses:
  • Audio equalisation / music analysis
  • Image compression (JPEG)
  • Noise removal
  • Medical imaging (MRI)
  • Telecommunications
"""
print(explanation)

# ─────────────────────────────────────────────────────────────
# BUILD A COMPOSITE SIGNAL
# ─────────────────────────────────────────────────────────────
sample_rate = 1000          # samples per second (Hz)
duration    = 1.0           # seconds
t = np.linspace(0, duration, int(sample_rate * duration), endpoint=False)

# Three sine waves we will mix together
f1, A1 = 5,  1.0    # 5 Hz,  amplitude 1.0
f2, A2 = 50, 0.5    # 50 Hz, amplitude 0.5
f3, A3 = 120, 0.25  # 120 Hz, amplitude 0.25

wave1 = A1 * np.sin(2 * np.pi * f1 * t)
wave2 = A2 * np.sin(2 * np.pi * f2 * t)
wave3 = A3 * np.sin(2 * np.pi * f3 * t)

composite = wave1 + wave2 + wave3

print(f"Signal built from three sine waves:")
print(f"  Wave 1: {f1} Hz, amplitude {A1}")
print(f"  Wave 2: {f2} Hz, amplitude {A2}")
print(f"  Wave 3: {f3} Hz, amplitude {A3}")
print(f"  Sample rate: {sample_rate} Hz | Duration: {duration} s")
print()

# ─────────────────────────────────────────────────────────────
# COMPUTE THE FFT
# ─────────────────────────────────────────────────────────────
N       = len(composite)
fft_raw = np.fft.fft(composite)                  # complex spectrum
freqs   = np.fft.fftfreq(N, d=1.0/sample_rate)  # frequency axis

# Keep only positive frequencies (the spectrum is symmetric for real signals)
pos_mask   = freqs >= 0
freqs_pos  = freqs[pos_mask]
amplitude  = (2 / N) * np.abs(fft_raw[pos_mask])  # normalised amplitude

# Find the dominant peaks
peak_indices = np.where(amplitude > 0.05)[0]
print("Detected frequency peaks (amplitude > 0.05):")
for idx in peak_indices:
    print(f"  {freqs_pos[idx]:.1f} Hz  →  amplitude {amplitude[idx]:.4f}")
print()

# ─────────────────────────────────────────────────────────────
# PLOT
# ─────────────────────────────────────────────────────────────
fig = plt.figure(figsize=(14, 10))
fig.suptitle("Fourier Transform Illustration", fontsize=15, fontweight="bold")
gs = GridSpec(3, 2, figure=fig, hspace=0.55, wspace=0.35)

# ── Row 0: individual component waves ──────────────────────
ax_w1 = fig.add_subplot(gs[0, 0])
ax_w2 = fig.add_subplot(gs[0, 1])

ax_w1.plot(t[:200], wave1[:200], color="steelblue")
ax_w1.set_title(f"Component 1: {f1} Hz, amp={A1}")
ax_w1.set_xlabel("Time (s)")
ax_w1.set_ylabel("Amplitude")
ax_w1.grid(True, alpha=0.3)

ax_w2.plot(t[:200], wave2[:200], color="darkorange")
ax_w2.set_title(f"Component 2: {f2} Hz, amp={A2}")
ax_w2.set_xlabel("Time (s)")
ax_w2.set_ylabel("Amplitude")
ax_w2.grid(True, alpha=0.3)

# ── Row 1: composite signal (time domain) ──────────────────
ax_time = fig.add_subplot(gs[1, :])
ax_time.plot(t[:300], composite[:300], color="darkgreen", linewidth=0.9)
ax_time.set_title("Composite Signal (time domain) — first 300 ms shown")
ax_time.set_xlabel("Time (s)")
ax_time.set_ylabel("Amplitude")
ax_time.grid(True, alpha=0.3)

# ── Row 2 left: frequency spectrum (FFT result) ────────────
ax_freq = fig.add_subplot(gs[2, 0])
ax_freq.plot(freqs_pos, amplitude, color="crimson", linewidth=1.2)
ax_freq.set_xlim(0, 200)
ax_freq.set_title("Frequency Spectrum (FFT output)")
ax_freq.set_xlabel("Frequency (Hz)")
ax_freq.set_ylabel("Amplitude")
ax_freq.grid(True, alpha=0.3)

# Annotate the peaks
for idx in peak_indices:
    ax_freq.annotate(
        f"{freqs_pos[idx]:.0f} Hz",
        xy=(freqs_pos[idx], amplitude[idx]),
        xytext=(freqs_pos[idx] + 5, amplitude[idx] + 0.05),
        fontsize=8,
        arrowprops=dict(arrowstyle="->", color="black", lw=0.8),
    )

# ── Row 2 right: stem plot for clarity ─────────────────────
ax_stem = fig.add_subplot(gs[2, 1])
# Only plot up to 200 Hz for clarity
mask200 = freqs_pos <= 200
markerline, stemlines, baseline = ax_stem.stem(
    freqs_pos[mask200], amplitude[mask200],
    linefmt="C4-", markerfmt="C4o", basefmt="k-"
)
plt.setp(stemlines, linewidth=0.8)
plt.setp(markerline, markersize=4)
ax_stem.set_title("Frequency Spectrum (stem plot)")
ax_stem.set_xlabel("Frequency (Hz)")
ax_stem.set_ylabel("Amplitude")
ax_stem.grid(True, alpha=0.3)

plt.savefig("fourier_transform_illustration.png", dpi=120, bbox_inches="tight")
print("Plot saved to fourier_transform_illustration.png")
plt.show()
print("Done.")